  ('locality-d0d1b9a2-moex-00299', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-ac2adf20', 'sub-locality-d0d1b9a2-02', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，X1年11月1日甲機關持有上市之Ａ公司普通股 500萬股，該投資之帳面價值為2億元，每股市價為39元，占Ａ公司股權比例為8%，該公司董 事長係由甲機關選派，X1年12月31日每股市價漲為41元，但Ａ公司之淨值未變動，其會計分 錄應為：', '["借：其他長期投資評價調整500萬元，貸：投資利益500萬元", "借：採權益法之投資評價調整1,000萬元，貸：投資利益1,000萬元", "借：採權益法之投資評價調整500萬元，貸：投資利益500萬元", "不作分錄"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "2e3990f47e39", "answer_pdf_sha1": "6b0b52294326", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
